public class MortgageCalculator {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        boolean running = true;

        while (running) {
            try {
                System.out.print("Enter principal loan amount (or 'exit' to quit): ");
                String input = scanner.nextLine().trim();

                if (input.equalsIgnoreCase("exit")) {
                    running = false;
                    continue;
                }

                double principal = Double.parseDouble(input);
                if (principal <= 0) {
                    System.out.println("Principal must be positive.");
                    continue;
                }

                System.out.print("Enter annual interest rate (%): ");
                double annualRate = Double.parseDouble(scanner.nextLine().trim());
                if (annualRate <= 0) {
                    System.out.println("Interest rate must be positive.");
                    continue;
                }

                System.out.print("Enter loan period (years): ");
                int years = Integer.parseInt(scanner.nextLine().trim());
                if (years <= 0) {
                    System.out.println("Loan period must be positive.");
                    continue;
                }

                double monthlyPayment = calculateMortgage(principal, annualRate, years);
                System.out.printf("Monthly mortgage payment: $%.2f%n", monthlyPayment);

            } catch (NumberFormatException e) {
                System.out.println("Invalid input. Please enter a valid number.");
            } catch (Exception e) {
                System.out.println("An error occurred: " + e.getMessage());
            }
        }
        scanner.close();
    }

    public static double calculateMortgage(double principal, double annualRate, int years) {
        double monthlyRate = annualRate / 100 / 12;
        int months = years * 12;
        return principal * monthlyRate * Math.pow(1 + monthlyRate, months) / (Math.pow(1 + monthlyRate, months) - 1);
    }
