namespace fs = std::filesystem;

void saveFilesToDirectory(const std::vector<std::string>& filenames, const std::string& directoryPath) {
    fs::path dirPath(directoryPath);

    // Check if directory exists and is writable
    if (!fs::exists(dirPath) || !fs::is_directory(dirPath)) {
        std::cerr << "Error: Directory does not exist or is not a directory." << std::endl;
        return;
    }

    std::error_code ec;
    fs::perms dirPerms = fs::status(dirPath, ec).permissions();
    if (ec || (dirPerms & fs::perms::owner_write) == fs::perms::none) {
        std::cerr << "Error: Directory is not writable." << std::endl;
        return;
    }

    for (const auto& filename : filenames) {
        fs::path filePath(filename);
        if (!fs::exists(filePath)) {
            std::cerr << "Error: File '" << filename << "' does not exist." << std::endl;
            continue;
        }

        fs::path destination = dirPath / filePath.filename();
        fs::rename(filePath, destination, ec);

        if (ec) {
            std::cerr << "Error: Failed to move file '" << filename << "': " << ec.message() << std::endl;
        } else {
            std::cout << "Success: Moved file '" << filename << "' to '" << directoryPath << "'." << std::endl;
        }
    }
}
