import java.io.File;
import java.io.FileNotFoundException;
import java.io.IOException;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;
import org.xml.sax.SAXException;

public class Configuration {
    private int port;
    private int timeout;

    public Configuration(int port, int timeout) {
        this.port = port;
        this.timeout = timeout;
    }

    public int getPort() {
        return port;
    }

    public int getTimeout() {
        return timeout;
    }
}

public class ConfigLoader {
    public static Configuration loadConfiguration(String filePath) throws FileNotFoundException, IOException, SAXException, ParserConfigurationException {
        File file = new File(filePath);
        if (!file.exists()) {
            throw new FileNotFoundException("Configuration file not found: " + filePath);
        }

        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(file);

        Element root = document.getDocumentElement();
        NodeList portNodes = root.getElementsByTagName("port");
        NodeList timeoutNodes = root.getElementsByTagName("timeout");

        if (portNodes.getLength() == 0 || timeoutNodes.getLength() == 0) {
            throw new SAXException("Required configuration tags (port or timeout) are missing in the XML file.");
        }

        Node portNode = portNodes.item(0);
        Node timeoutNode = timeoutNodes.item(0);

        int port;
        int timeout;

        try {
            port = Integer.parseInt(portNode.getTextContent());
            timeout = Integer.parseInt(timeoutNode.getTextContent());
        } catch (NumberFormatException e) {
            throw new SAXException("Invalid format for port or timeout in the XML file.");
        }

        return new Configuration(port, timeout);
    }
}
