use std::str::FromStr;

fn filter_above_threshold<T>(values: &[T], threshold: T) -> Vec<T>
where
    T: PartialOrd + Copy,
{
    values.iter().filter(|&&x| x <= threshold).cloned().collect()
}

fn filter_above_threshold_with_error_handling<T>(values: &[Option<T>], threshold: T) -> Result<Vec<T>, String>
where
    T: PartialOrd + Copy + Display,
{
    let mut result = Vec::new();
    for value in values {
        match value {
            Some(v) => {
                if *v <= threshold {
                    result.push(*v);
                }
            }
            None => return Err("Encountered nil value".to_string()),
        }
    }
    Ok(result)
}

fn filter_above_threshold_mixed(values: &[String], threshold: f64) -> Result<Vec<f64>, String> {
    let mut result = Vec::new();
    for value in values {
        match value.parse::<f64>() {
            Ok(v) => {
                if v <= threshold {
                    result.push(v);
                }
            }
            Err(_) => return Err(format!("Non-numeric value found: {}", value)),
        }
    }
    Ok(result)
}
