using namespace std;

vector<int> traverseGraph(const vector<vector<int>>& adjacencyMatrix, int startNode) {
    if (adjacencyMatrix.empty() || adjacencyMatrix.size() != adjacencyMatrix[0].size()) {
        throw invalid_argument("Invalid adjacency matrix: must be square and non-empty.");
    }

    int numNodes = adjacencyMatrix.size();
    if (startNode < 0 || startNode >= numNodes) {
        throw out_of_range("Starting node index is out of bounds.");
    }

    vector<bool> visited(numNodes, false);
    queue<int> q;
    vector<int> traversalOrder;

    q.push(startNode);
    visited[startNode] = true;

    while (!q.empty()) {
        int currentNode = q.front();
        q.pop();
        traversalOrder.push_back(currentNode);

        for (int neighbor = 0; neighbor < numNodes; ++neighbor) {
            if (adjacencyMatrix[currentNode][neighbor] == 1 && !visited[neighbor]) {
                visited[neighbor] = true;
                q.push(neighbor);
            }
        }
    }

    return traversalOrder;
}
