#include <iostream>

// Node structure for singly linked list
struct Node {
    int value;      // Integer value stored in the node
    Node* next;     // Pointer to the next node in the list
};

/**
 * Processes a singly linked list by multiplying each node's value by its 1-indexed position.
 * 
 * @param head Pointer to the head of the linked list.
 * @return Pointer to the head of the modified linked list.
 * 
 * Edge cases handled:
 * - Empty list (returns nullptr).
 * - Single-node list (multiplies value by 1).
 */
Node* processLinkedList(Node* head) {
    if (head == nullptr) {
        return nullptr; // Handle empty list
    }

    Node* current = head;
    int position = 1; // 1-indexed position

    while (current != nullptr) {
        current->value *= position; // Multiply value by position
        current = current->next;    // Move to next node
        position++;                 // Increment position
    }

    return head; // Return modified list
}

/**
 * Utility function to print the linked list (for testing purposes).
 * 
 * @param head Pointer to the head of the linked list.
 */
void printLinkedList(Node* head) {
    Node* current = head;
    while (current != nullptr) {
        std::cout << current->value << " ";
        current = current->next;
    }
    std::cout << std::endl;
}

/**
 * Utility function to delete the linked list (for memory cleanup).
 * 
 * @param head Pointer to the head of the linked list.
 */
void deleteLinkedList(Node* head) {
    Node* current = head;
    while (current != nullptr) {
        Node* next = current->next;
        delete current;
        current = next;
    }
}
