/**
 * This class provides a utility function to analyze a set of integers.
 */
public class UniqueElementAnalyzer {

    /**
     * Analyzes a set of integers to compute the maximum, minimum, and arithmetic mean.
     *
     * @param numbers A Set of integers to be analyzed. Must not be empty.
     * @return An array of doubles where:
     *         - index 0 contains the minimum value,
     *         - index 1 contains the maximum value,
     *         - index 2 contains the arithmetic mean.
     * @throws EmptySetException If the input set is empty.
     */
    public static double[] uniqueElementAnalyzer(Set<Integer> numbers) throws EmptySetException {
        if (numbers.isEmpty()) {
            throw new EmptySetException("The input set cannot be empty.");
        }

        int min = Integer.MAX_VALUE;
        int max = Integer.MIN_VALUE;
        double sum = 0;

        for (int num : numbers) {
            if (num < min) {
                min = num;
            }
            if (num > max) {
                max = num;
            }
            sum += num;
        }

        double mean = sum / numbers.size();
        return new double[]{min, max, mean};
    }
}

/**
 * Custom exception thrown when the input set is empty.
 */
class EmptySetException extends Exception {
    public EmptySetException(String message) {
        super(message);
    }
