        return result;
    }

    double min = std::numeric_limits<double>::max();
    double max = std::numeric_limits<double>::lowest();
    double sum = 0.0;
    int count = 0;

    for (const auto& pair : data) {
        if (pair.second < 0) {
            throw std::invalid_argument("Data values must be non-negative.");
        }

        if (pair.second < min) {
            min = pair.second;
        }
        if (pair.second > max) {
            max = pair.second;
        }
        sum += pair.second;
        count++;
    }

    result["min"] = min;
    result["max"] = max;
    result["sum"] = sum;
    result["average"] = sum / count;

    return result;
