use std::collections::{HashMap, HashSet, VecDeque};

#[derive(Debug)]
pub enum GraphError {
    NodeNotFound,
    NoPathExists,
}

pub struct Graph {
    adjacency_list: HashMap<usize, Vec<usize>>,
}

impl Graph {
    pub fn new() -> Self {
        Graph {
            adjacency_list: HashMap::new(),
        }
    }

    pub fn add_edge(&mut self, from: usize, to: usize) {
        self.adjacency_list.entry(from).or_insert(Vec::new()).push(to);
    }

    pub fn contains_node(&self, node: usize) -> bool {
        self.adjacency_list.contains_key(&node)
    }
}

pub enum TraversalMethod {
    DFS,
    BFS,
}

pub fn find_path(
    graph: &Graph,
    start: usize,
    end: usize,
    method: TraversalMethod,
) -> Result<Vec<usize>, GraphError> {
    if !graph.contains_node(start) || !graph.contains_node(end) {
        return Err(GraphError::NodeNotFound);
    }

    match method {
        TraversalMethod::DFS => dfs(graph, start, end),
        TraversalMethod::BFS => bfs(graph, start, end),
    }
}

fn dfs(graph: &Graph, start: usize, end: usize) -> Result<Vec<usize>, GraphError> {
    let mut visited = HashSet::new();
    let mut path = Vec::new();
    if dfs_helper(graph, start, end, &mut visited, &mut path) {
        Ok(path)
    } else {
        Err(GraphError::NoPathExists)
    }
}

fn dfs_helper(
    graph: &Graph,
    current: usize,
    end: usize,
    visited: &mut HashSet<usize>,
    path: &mut Vec<usize>,
) -> bool {
    visited.insert(current);
    path.push(current);

    if current == end {
        return true;
    }

    if let Some(neighbors) = graph.adjacency_list.get(&current) {
        for &neighbor in neighbors {
            if !visited.contains(&neighbor) {
                if dfs_helper(graph, neighbor, end, visited, path) {
                    return true;
                }
            }
        }
    }

    path.pop();
    false
}

fn bfs(graph: &Graph, start: usize, end: usize) -> Result<Vec<usize>, GraphError> {
    let mut visited = HashSet::new();
    let mut queue = VecDeque::new();
    let mut parent = HashMap::new();

    queue.push_back(start);
    visited.insert(start);

    while let Some(current) = queue.pop_front() {
        if current == end {
            let mut path = Vec::new();
            let mut node = end;
            while node != start {
                path.push(node);
                node = parent[&node];
            }
            path.push(start);
            path.reverse();
            return Ok(path);
        }

        if let Some(neighbors) = graph.adjacency_list.get(&current) {
            for &neighbor in neighbors {
                if !visited.contains(&neighbor) {
                    visited.insert(neighbor);
                    parent.insert(neighbor, current);
                    queue.push_back(neighbor);
                }
            }
        }
    }

    Err(GraphError::NoPathExists)
}
