using namespace std;

vector<int> findShortestPath(const unordered_map<int, vector<pair<int, int>>>& graph, int start, int end) {
    if (graph.find(start) == graph.end()) {
        throw invalid_argument("Starting node does not exist in the graph.");
    }
    if (graph.find(end) == graph.end()) {
        throw invalid_argument("Ending node does not exist in the graph.");
    }

    unordered_map<int, int> distances;
    unordered_map<int, int> predecessors;
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;

    for (const auto& node : graph) {
        distances[node.first] = INT_MAX;
    }
    distances[start] = 0;
    pq.push({0, start});

    while (!pq.empty()) {
        int current_node = pq.top().second;
        int current_distance = pq.top().first;
        pq.pop();

        if (current_distance > distances[current_node]) {
            continue;
        }

        for (const auto& neighbor : graph.at(current_node)) {
            int next_node = neighbor.first;
            int weight = neighbor.second;
            int distance = current_distance + weight;

            if (distance < distances[next_node]) {
                distances[next_node] = distance;
                predecessors[next_node] = current_node;
                pq.push({distance, next_node});
            }
        }
    }

    if (distances[end] == INT_MAX) {
        return {};
    }

    vector<int> path;
    for (int at = end; at != start; at = predecessors[at]) {
        path.push_back(at);
    }
    path.push_back(start);
    reverse(path.begin(), path.end());

    return path;
}
