def calculateWaterRetention(elevation_map):
    if not elevation_map or not elevation_map[0]:
        return 0

    m, n = len(elevation_map), len(elevation_map[0])
    visited = [[False for _ in range(n)] for _ in range(m)]
    heap = []

    for i in range(m):
        for j in range(n):
            if i == 0 or i == m - 1 or j == 0 or j == n - 1:
                heapq.heappush(heap, (elevation_map[i][j], i, j))
                visited[i][j] = True

    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]
    water = 0
    max_height = 0

    while heap:
        height, x, y = heapq.heappop(heap)
        max_height = max(max_height, height)
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < m and 0 <= ny < n and not visited[nx][ny]:
                if elevation_map[nx][ny] < max_height:
                    water += max_height - elevation_map[nx][ny]
                heapq.heappush(heap, (elevation_map[nx][ny], nx, ny))
                visited[nx][ny] = True
    return water
