public class GraphTraversal {
    public static List<Integer> analyzeGraphTraversal(Map<Integer, List<Integer>> graph, boolean useBFS) {
        List<Integer> visitedOrder = new ArrayList<>();
        if (graph == null || graph.isEmpty()) {
            System.err.println("Graph is empty or null.");
            return visitedOrder;
        }

        Set<Integer> visited = new HashSet<>();
        for (int node : graph.keySet()) {
            if (!visited.contains(node)) {
                if (useBFS) {
                    bfs(graph, node, visited, visitedOrder);
                } else {
                    dfs(graph, node, visited, visitedOrder);
                }
            }
        }
        return visitedOrder;
    }

    private static void bfs(Map<Integer, List<Integer>> graph, int start, Set<Integer> visited, List<Integer> visitedOrder) {
        Queue<Integer> queue = new LinkedList<>();
        queue.add(start);
        visited.add(start);

        while (!queue.isEmpty()) {
            int current = queue.poll();
            visitedOrder.add(current);

            for (int neighbor : graph.getOrDefault(current, Collections.emptyList())) {
                if (!visited.contains(neighbor)) {
                    visited.add(neighbor);
                    queue.add(neighbor);
                }
            }
        }
    }

    private static void dfs(Map<Integer, List<Integer>> graph, int start, Set<Integer> visited, List<Integer> visitedOrder) {
