vector<int> computeShortestPathFromNode(const vector<vector<int>>& graph, int startNode) {
    if (startNode < 0 || startNode >= graph.size()) {
        throw out_of_range("Starting node index is out of bounds.");
    }

    int n = graph.size();
    vector<int> distances(n, INT_MAX);
    distances[startNode] = 0;

    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    pq.push({0, startNode});

    while (!pq.empty()) {
        int currentDist = pq.top().first;
        int u = pq.top().second;
        pq.pop();

        if (currentDist > distances[u]) {
            continue;
        }

        for (int v = 0; v < n; ++v) {
            if (graph[u][v] != 0) {
                int newDist = currentDist + graph[u][v];
                if (newDist < distances[v]) {
                    distances[v] = newDist;
                    pq.push({newDist, v});
                }
            }
        }
    }

    return distances;
}
