use std::collections::HashMap;

struct UserData {
    age: Option<u32>,
    occupation: Option<String>,
    city: Option<String>,
}

struct Statistics {
    average_age: f64,
    most_frequent_occupation: Option<String>,
    most_common_city: Option<String>,
}

fn aggregate_user_data(user_map: HashMap<String, UserData>) -> Result<Statistics, String> {
    if user_map.is_empty() {
        return Err("User map is empty".to_string());
    }

    let mut total_age = 0;
    let mut age_count = 0;
    let mut occupation_counts: HashMap<String, u32> = HashMap::new();
    let mut city_counts: HashMap<String, u32> = HashMap::new();

    for (_, user_data) in user_map.iter() {
        if let Some(age) = user_data.age {
            total_age += age;
            age_count += 1;
        }

        if let Some(occupation) = &user_data.occupation {
            *occupation_counts.entry(occupation.clone()).or_insert(0) += 1;
        }

        if let Some(city) = &user_data.city {
            *city_counts.entry(city.clone()).or_insert(0) += 1;
        }
    }

    if age_count == 0 {
        return Err("No valid age data found".to_string());
    }

    let average_age = total_age as f64 / age_count as f64;

    let most_frequent_occupation = occupation_counts
        .into_iter()
        .max_by_key(|(_, count)| *count)
        .map(|(occupation, _)| occupation);

    let most_common_city = city_counts
        .into_iter()
        .max_by_key(|(_, count)| *count)
        .map(|(city, _)| city);

    Ok(Statistics {
        average_age,
        most_frequent_occupation,
        most_common_city,
    })
}

fn main() {
    let mut user_map = HashMap::new();
    user_map.insert(
        "user1".to_string(),
        UserData {
            age: Some(25),
            occupation: Some("Engineer".to_string()),
            city: Some("New York".to_string()),
        },
    );
    user_map.insert(
        "user2".to_string(),
        UserData {
            age: Some(30),
            occupation: Some("Doctor".to_string()),
            city: Some("New York".to_string()),
        },
    );
    user_map.insert(
        "user3".to_string(),
        UserData {
            age: Some(35),
            occupation: Some("Engineer".to_string()),
            city: Some("Chicago".to_string()),
        },
    );

    match aggregate_user_data(user_map) {
        Ok(stats) => {
            println!("Average Age: {}", stats.average_age);
            println!(
                "Most Frequent Occupation: {}",
                stats.most_frequent_occupation.unwrap_or("N/A".to_string())
            );
            println!(
                "Most Common City: {}",
                stats.most_common_city.unwrap_or("N/A".to_string())
            );
        }
        Err(e) => println!("Error: {}", e),
    }
}
