public class RoadNetworkAnalyzer {
    public static void analyzeRoadNetwork(int[][] matrix, int[] junction) {
        try {
            int row = junction[0];
            int col = junction[1];

            if (row < 0 || row >= matrix.length || col < 0 || col >= matrix[0].length) {
                throw new IndexOutOfBoundsException("Junction position is out of matrix boundaries.");
            }

            System.out.println("Direct connections from junction " + Arrays.toString(junction) + ":");

            // Check all four possible directions (up, down, left, right)
            if (row > 0 && matrix[row - 1][col] == 1) {
                System.out.println("Up: " + (row - 1) + "," + col);
            }
            if (row < matrix.length - 1 && matrix[row + 1][col] == 1) {
                System.out.println("Down: " + (row + 1) + "," + col);
            }
            if (col > 0 && matrix[row][col - 1] == 1) {
                System.out.println("Left: " + row + "," + (col - 1));
            }
            if (col < matrix[0].length - 1 && matrix[row][col + 1] == 1) {
                System.out.println("Right: " + row + "," + (col + 1));
            }
        } catch (IndexOutOfBoundsException e) {
            System.err.println("Error: " + e.getMessage());
        } catch (Exception e) {
            System.err.println("Unexpected error: " + e.getMessage());
        }
    }
